import { InitializationError } from "./errors";
import { InternalBehaviorMapsResource } from "./internal-resources/behavior-maps";
import type {
	BehaviorMapExport,
	InternalConduitClientOptions,
} from "./internal-types";
import { Transport } from "./resources/transport";

type InternalConduitBehaviorMaps = {
	get: (
		entityId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	) => Promise<BehaviorMapExport>;
};

class InternalConduit {
	public readonly behaviorMaps: InternalConduitBehaviorMaps;

	constructor(options: InternalConduitClientOptions) {
		if (!options.internalApiKey) {
			throw new InitializationError("internalApiKey is required", {
				code: "config_error",
			});
		}
		if (isBrowserRuntime() && !options.dangerouslyAllowBrowser) {
			throw new InitializationError(
				"Conduit internal SDK cannot run in browser environments by default because internal API keys are secret. Use a server/edge proxy or pass dangerouslyAllowBrowser: true only if you understand the risk.",
				{ code: "unsupported_runtime" },
			);
		}

		const baseUrl = options.baseUrl ?? "https://api.mappa.ai";
		if (!isValidUrl(baseUrl)) {
			throw new InitializationError("baseUrl must be a valid URL", {
				code: "config_error",
			});
		}

		const transport = new Transport({
			apiKey: options.internalApiKey,
			authHeaderName: "x-internal-key",
			baseUrl,
			defaultHeaders: options.defaultHeaders,
			fetch: options.fetch,
			maxRetries: options.maxRetries ?? 2,
			telemetry: options.telemetry,
			timeoutMs: options.timeoutMs ?? 300000,
			userAgent: options.userAgent,
		});

		const behaviorMaps = new InternalBehaviorMapsResource(transport);
		this.behaviorMaps = {
			get: behaviorMaps.get.bind(behaviorMaps),
		};
	}
}

function isBrowserRuntime(): boolean {
	if (typeof globalThis.window === "undefined") return false;
	if (typeof document === "undefined") return false;
	return true;
}

function isValidUrl(value: string): boolean {
	try {
		new URL(value);
		return true;
	} catch {
		return false;
	}
}

export type { InternalConduitClientOptions } from "./internal-types";
export { InternalConduit };
